import { useCanvas } from '../hooks/useCanvas.js';
import {
  type DotCanvasProps,
  LineCanvasInstance,
} from '../types/canvas-shape.js';
import { printDotBuilder } from '../utils/shapes/dot-canvas.js';

export function DotCanvas<Datum>(props: DotCanvasProps<Datum>) {
  const { radius, enableDotOverflow = false, shape, ...propsDotCanvas } = props;

  const drawDot = printDotBuilder<Datum>(radius, enableDotOverflow, shape);

  const drawDotCanvas = (
    ctx: CanvasRenderingContext2D,
    canvas: LineCanvasInstance<Datum>,
  ) => {
    drawDot(ctx, canvas, canvas.x, canvas.y);
    return false;
  };

  useCanvas('dot', (ctx) => drawDotCanvas(ctx, propsDotCanvas));

  return null;
}
